   444|  const request = reqSnap.data();
   445|  if (!request.allowChat) throw new Error('Chat is not active for this request');
   446|
   447|  const isParticipant = request.customerUid === senderUid || request.providerUid === senderUid;
   448|  if (!isParticipant) throw new Error('You are not a participant in this request');
   449|
   450|  const docRef = await addDoc(
