    37|async function handleCloudinaryDelete(request: Request, env: Env): Promise<Response> {
    38|  try {
    39|    const body = await request.json() as { publicId?: string };
    40|
    41|    if (!body.publicId) {
    42|      return jsonResponse({ success: false, error: 'publicId is required' }, 400);
    43|    }
    44|
    45|    const timestamp = Math.floor(Date.now() / 1000).toString();
    46|
    47|    const signaturePayload = `public_id=${body.publicId}&timestamp=${timestamp}${env.CLOUDINARY_API_SECRET}`;
    48|    const encoder = new TextEncoder();
    49|    const data = encoder.encode(signaturePayload);
    50|    const hashBuffer = await crypto.subtle.digest('SHA-1', data);
    51|    const hashArray = Array.from(new Uint8Array(hashBuffer));
    52|    const signature = hashArray.map((b) => b.toString(16).padStart(2, '0')).join('');
    53|
    54|    const formData = new FormData();
    55|    formData.append('public_id', body.publicId);
    56|    formData.append('timestamp', timestamp);
    57|    formData.append('api_key', env.CLOUDINARY_API_KEY);
